import type { ImageViewerContextProps } from './useImageViewer';
import { createContextHook } from '@universe-design/react-utilities';

export const { Provider: ImageViewerContextProvider, useContext: useImageViewerContext } =
  createContextHook<ImageViewerContextProps>('ImageViewerContext', {
    strict: true,
  });

export const useImageViewerContextExternal = () => {
  const { currentIndex, setCurrentIndex, getMatrix, setMatrix, scale, rotationRadians, isImageContained } =
    useImageViewerContext();
  return {
    currentIndex,
    setCurrentIndex,
    getMatrix,
    setMatrix,
    scale,
    rotationRadians,
    isImageContained,
  };
};
